draw(rightanglemark(C,F,B,10));
draw(rightanglemark(A,D,C,10));
label("$A$", A, N);
label("$B$", B, SW);
label("$C$", C, SE);
label("$D$", D, S);
label("$E$", E, NE);
label("$F$", F, NW);
